// // This module implements a 3-bit Johnson counter. On each rising edge of the clock, the bits are shifted to the right, and the inverted value of the first bit is shifted into the last bit.
module johnson_counter(clk, reset, q);

    input clk;
    input reset;
    output [2:0] q;
    reg [2:0] q;
    initial q = 3'b000;

    always @(posedge clk)
        begin
            if (reset)
                q <= 3'b000;
            else
                q <= {q[1:0], ~q[2]};
        end

endmodule
